from crewai import Task

@vex.task_callback
def verify_research_output(task_output):
    """Verify research agent output before delegation"""
    return vex.verify(
        content=task_output,
        specs={
            'factual_accuracy': True,
            'source_citation': True,
            'completeness': {'min_facts': 5}
        }
    )

research_task = Task(
    description='Research {topic}...',
    agent=researcher,
    callback=verify_research_output,  # Vex integration point
    outputs={'raw_facts': 'json'}
)

@vex.task_callback
def verify_brand_voice(content):
    """Enforce brand voice consistency"""
    return vex.verify(
        content=content,
        specs={
            'brand_consistency': {
                'voice': 'professional, approachable',
                'brand': 'Vex AI'
            },
            'tone_adherence': True
        }
    )

VEX_SPECS = {
    'researcher': {
        'factual_accuracy': {'weight': 1.0},
        'source_quality': {'min_domains': 3},
        'completeness': {'min_facts': 8}
    },
    'writer': {
        'brand_consistency': {'voice': 'professional approachable'},
        'originality': {'min_score': 0.95},
        'tone_adherence': {'target_tone': 'authoritative'}
    },
    'editor': {
        'factual_accuracy': {'weight': 0.8},
        'grammar_quality': {'max_errors': 0},
        'readability': {'flesch_score': 65}
    },
    'seo_optimizer': {
        'seo_compliance': {'primary_keyword': True},
        'keyword_density': {'optimal_range': [1.5, 2.5]},
        'meta_optimization': True
    }
}

def get_vex_callback(agent_role):
    def callback(task_output):
        specs = VEX_SPECS.get(agent_role, {})
        return vex.verify(content=task_output, specs=specs)
    return callback

# Apply to tasks
writer_task.callback = get_vex_callback('writer')
seo_task.callback = get_vex_callback('seo_optimizer')

class VexGuardedCrew:
    def __init__(self, crew, max_retries=2):
        self.crew = crew
        self.max_retries = max_retries

    def safe_kickoff(self, inputs):
        for attempt in range(self.max_retries + 1):
            result = self.crew.kickoff(inputs=inputs)

            # Final Vex verification
            final_check = vex.verify(
                content=result['optimized_content'],
                specs=verification_specs,
                context={'all_outputs': result}
            )

            if final_check['passed']:
                return result
            elif attempt < self.max_retries:
                print(f'Retry {attempt + 1}/{self.max_retries} - Issues: {final_check["issues"]}')
                inputs['context'] = final_check['feedback']
            else:
                # Escalate to human
                vex.escalate(
                    content=result['optimized_content'],
                    issues=final_check['issues'],
                    metadata=inputs
                )
                raise ValueError('Content failed final verification')

# Usage
guarded_crew = VexGuardedCrew(content_crew)
final_content = guarded_crew.safe_kickoff(content_inputs)
